import React, { useState } from "react";
import LazyLoad from "react-lazyload";

function Allbranch() {
  const [activeIndex, setActiveIndex] = useState(0);

  const schools = [
    {
      title: "DPS Hyderabad",
      img: "/images/Dpghyderabad.webp",
      alt: "dps hyderabad",
      levels: ["Pre-Primary"],
    },
    {
      title: "DPS Miyapur",
      img: "/images/Dpghyderabad.webp",
      alt: "dps miyapur",
      levels: ["Pre-Primary"],
    },
    {
      title: "DPS Secunderabad",
      img: "/images/Dpghyderabad.webp",
      alt: "dps secunderabad",
      levels: ["Pre-Primary"],
    },
  ];

  return (
    <section className="dps_family_section ">
      <div className="dps_family_carousel">
        {schools.map((school, index) => (
          <div
            key={index}
            className={`family-card ${activeIndex === index ? "active" : ""}`}
            onClick={() => setActiveIndex(index)}
          >
            <LazyLoad height={200} once>
              <img src={school.img} alt={school.alt} className="family-image" />
            </LazyLoad>

            {activeIndex === index ? (
              <div className="school-info">
                <div className="school_content">
                  <h4>{school.title}</h4>

                  <div className="list_btn">
                    <ul>
                      {school.levels.map((level, i) => (
                        <li key={i}>{level}</li>
                      ))}
                    </ul>

                    <div className="learn-btn">Learn More</div>
                  </div>
                </div>
              </div>
            ) : (
              <div className="overlay">
                <span>{school.title}</span>
              </div>
            )}
          </div>
        ))}
      </div>
    </section>
  );
}

export default Allbranch;

