import { useState, useEffect } from "react";
import Slider from "react-slick";
import "slick-carousel/slick/slick.css";
import "slick-carousel/slick/slick-theme.css";
import SingleFacility from "./SingleFacility";

const facilities = [
  { name: "Students", image: "/images/student_fac.jpg" },
  { name: "Infirmary", image: "/images/infirmary_fac.jpg" },
  { name: "Sports Facilities", image: "/images/sport_fac.jpg" },
  { name: "Laboratory", image: "/images/lab_fac.jpg" },
  { name: "Transport", image: "/images/transport-fac.jpg" },
];

function Facilities() {
  const [windowWidth, setWindowWidth] = useState(window.innerWidth);

  useEffect(() => {
    const handleResize = () => setWindowWidth(window.innerWidth);
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  const settings = {
    dots: true,
    infinite: true,
    speed: 500,
    slidesToShow: 2,
    slidesToScroll: 1,
    autoplay: true,
    autoplaySpeed: 3000,
    responsive: [
      {
        breakpoint: 768,
        settings: {
          slidesToShow: 1,
          slidesToScroll: 1,
        },
      },
    ],
  };

  return (
    <section className="facilities_home custom-padding">
      {windowWidth >= 992 ? (
        <div className="facilities_row">
          {facilities.map((item, index) => (
            <SingleFacility key={index} facility={item} />
          ))}
        </div>
      ) : (
        <Slider {...settings}>
          {facilities.map((item, index) => (
            <SingleFacility key={index} facility={item} />
          ))}
        </Slider>
      )}
    </section>
  );
}

export default Facilities;

