import React, { useEffect, useState, useRef } from "react";
import { Link } from "react-router-dom";
import { getHighlight } from "../Service/Api";
import LazyLoad from "react-lazyload";
// import "../assets/css/style.css";
import GetInTouch from "./GetInTouch";
function Header() {
  const [data, setData] = useState([]);
  const [menuOpen, setMenuOpen] = useState(false);
  const [isMobile, setIsMobile] = useState(false);
  const marqueeRef = useRef(null);

  useEffect(() => {
    const getData = async () => {
      const res = await getHighlight();
      setData(res);
    };
    getData();
  }, []);

  const emptyArray = [
    { description: "Stay tuned for latest updates" },
    { description: "Stay tuned for latest updates" },
    { description: "Stay tuned for latest updates" },
  ];

  // close menu on outside click (mobile)
  useEffect(() => {
    const handleClickOutside = (e) => {
      const menu = document.querySelector(".menu");
      const button = document.getElementById("resp-menu");
      if (
        menu &&
        button &&
        !menu.contains(e.target) &&
        !button.contains(e.target)
      ) {
        setMenuOpen(false);
      }
    };
    document.addEventListener("click", handleClickOutside);
    document.addEventListener("touchstart", handleClickOutside);
    return () => {
      document.removeEventListener("click", handleClickOutside);
      document.removeEventListener("touchstart", handleClickOutside);
    };
  }, []);

  useEffect(() => {
    const mediaQuery = window.matchMedia("(max-width: 991.98px)");
    const handleChange = (event) => {
      setIsMobile(event.matches);
    };
    setIsMobile(mediaQuery.matches);
    if (mediaQuery.addEventListener) {
      mediaQuery.addEventListener("change", handleChange);
      return () => mediaQuery.removeEventListener("change", handleChange);
    }
    mediaQuery.addListener(handleChange);
    return () => mediaQuery.removeListener(handleChange);
  }, []);

  useEffect(() => {
    const menu = document.querySelector(".menu");
    if (!menu) {
      return;
    }

    const items = menu.querySelectorAll("li");
    const handleEnter = (e) => {
      const li = e.currentTarget;
      const submenu = li.querySelector(":scope > ul");
      if (!submenu) {
        return;
      }
      submenu.classList.remove("submenu-left");
      const rect = submenu.getBoundingClientRect();
      if (rect.right > window.innerWidth) {
        submenu.classList.add("submenu-left");
      }
    };
    const handleLeave = (e) => {
      const li = e.currentTarget;
      const submenu = li.querySelector(":scope > ul");
      if (submenu) {
        submenu.classList.remove("submenu-left");
      }
    };
    const handleResize = () => {
      menu
        .querySelectorAll("ul.submenu-left")
        .forEach((ul) => ul.classList.remove("submenu-left"));
    };

    items.forEach((li) => {
      if (li.querySelector(":scope > ul")) {
        li.addEventListener("mouseenter", handleEnter);
        li.addEventListener("mouseleave", handleLeave);
      }
    });
    window.addEventListener("resize", handleResize);
    return () => {
      items.forEach((li) => {
        if (li.querySelector(":scope > ul")) {
          li.removeEventListener("mouseenter", handleEnter);
          li.removeEventListener("mouseleave", handleLeave);
        }
      });
      window.removeEventListener("resize", handleResize);
    };
  }, []);

  useEffect(() => {
    const menu = document.querySelector(".menu");
    if (!menu) {
      return;
    }

    menu.querySelectorAll("li").forEach((li) => {
      if (li.querySelector(":scope > ul")) {
        li.classList.add("has-submenu");
      }
    });

    const handleMenuClick = (e) => {
      if (!isMobile) {
        return;
      }
      const link = e.target.closest(".menu li > a");
      if (!link) {
        return;
      }
      const li = link.parentElement;
      const submenu = li.querySelector(":scope > ul");
      if (!submenu) {
        return;
      }
      e.preventDefault();
      e.stopPropagation();
      const isOpen = li.classList.contains("submenu-open");
      const siblingScope =
        li.parentElement
          ?.closest("li.submenu-open")
          ?.querySelector(":scope > ul") || menu;
      siblingScope
        .querySelectorAll(":scope > li.submenu-open")
        .forEach((openLi) => openLi.classList.remove("submenu-open"));
      if (!isOpen) {
        li.classList.add("submenu-open");
      }
    };

    menu.addEventListener("click", handleMenuClick);
    return () => {
      menu.removeEventListener("click", handleMenuClick);
    };
  }, [isMobile]);

  useEffect(() => {
    if (!menuOpen) {
      document
        .querySelectorAll(".menu li.submenu-open")
        .forEach((li) => li.classList.remove("submenu-open"));
    }
  }, [menuOpen]);
  return (
