        </div>
        <marquee
          onMouseOver={(event) => event.currentTarget.stop()}
          onMouseOut={(event) => event.currentTarget.start()}
        >
          {data.length > 0
            ? data.map((item, index) => (
                <p>
                  {item.title}
                  {item.attachments.length > 0 && (
                    <a
                      href={`https://webapi.entab.info/api/image/${item.attachments[0]}`}
                      target="_blank"
                      rel="noopener noreferrer"
                      key={index}
                    >
                      <i
                        style={{ color: "white" }}
                        className="bi bi-paperclip"
                      ></i>
                    </a>
                  )}
                  |
                </p>
              ))
            : emptyArray.map((data, index) => (
                <a key={index}>{data.description}</a>
              ))}
        </marquee>
      </div>
      <section className="topbarsec">
        <div className="container-fluid">
