import React, { useEffect, useState } from "react";
import Carousel from "react-bootstrap/Carousel";
import { Link } from "react-router-dom";
import { getPrincipalMessage } from "../Service/Api";

function Homemesdesk() {
  const [data, setData] = useState([]);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const fetchedData = await getPrincipalMessage();
        setData(fetchedData);
      } catch (error) {
        console.error("Error fetching data:", error);
      }
    };
    fetchData();
  }, []);

  // Remove HTML tags
  function stripHtmlTags(html) {
    const div = document.createElement("div");
    div.innerHTML = html;
    return div.textContent || div.innerText || "";
  }

  const getImageUrl = (item, fallback) => {
    return item?.attachments && item.attachments.length > 0
      ? `https://webapi.entab.info/api/image/${item.attachments[0]}`
      : fallback;
  };

  return (
    <div className="message-sec py-5">
      <div className="container">
        <Carousel
          controls={true}
          indicators={true}
          prevIcon={<i className="bi bi-chevron-left fs-1 text-dark"></i>}
          nextIcon={<i className="bi bi-chevron-right fs-1 text-dark"></i>}
        >
          {/* Chairman */}
          <Carousel.Item>
            <div className="row msg align-items-center">
              <div className="col-lg-7 col-md-12">
                {data
                  .filter((item) => item.category === "Chairman")
                  .map((item, index) => (
                    <div key={index}>
                      <p>{stripHtmlTags(item.message)}</p>
                      <div className="clr"></div>
                      <div className="name-board">
                        <h3>{item.name}</h3>
                        <p>Chairman</p>
                      </div>
                    </div>
                  ))}
              </div>
              <div className="col-lg-5 col-md-12 text-center">
                {data
                  .filter((item) => item.category === "Chairman")
                  .map((item, index) => (
                    <img
                      key={index}
                      src={getImageUrl(
                        item,
                        "https://via.placeholder.com/400x400?text=Chairman"
                      )}
                      className="img-fluid"
                      alt="Chairman"
                    />
                  ))}
              </div>
            </div>
            <Link to="/chairman-message">Read More</Link>
          </Carousel.Item>

          {/* Pro-Vice Chairman (Static Content) */}
          <Carousel.Item>
            <div className="row msg align-items-center">
              <div className="col-lg-7 col-md-12">
                <p>
                  A decade and a half ago, when we set out to bring the Delhi
                  Public School brand of schooling to Hyderabad, we were
                  brimming with enthusiasm and anticipation. Over the years we
                  have seen numerous batches of our students take on the world
                  and begin to look at our efforts with a sense of satisfaction
                  for having made a difference to the lives of our alumni and
                  their families. The objective of ensuring value-based
                  education is imparted without compromising on high academic
                  standards and it has been the predominant motivator over the
                  years and continues to be the bedrock of our school.
                </p>
                <div className="clr"></div>
                <div className="name-board">
                  <h3>Shri. Umanadh</h3>
                  <p>Pro-Vice Chairman</p>
                </div>
              </div>
              <div className="col-lg-5 col-md-12 text-center">
                <img
                  src="https://webapi.entab.info/api/image/DPSH/public/Vice-Chairman.jpg"
                  className="img-fluid"
                  alt="Vice Chairman"
                />
              </div>
            </div>
            <Link to="/vice-chairmans-message">Read More</Link>
          </Carousel.Item>

          {/* Director */}
          <Carousel.Item>
            <div className="row msg align-items-center">
              <div className="col-lg-7 col-md-12">
                {data
                  .filter((item) => item.category === "Director")
                  .map((item, index) => (
                    <div key={index}>
                      <p>{stripHtmlTags(item.message)}</p>
                      <div className="clr"></div>
                      <div className="name-board">
                        <h3>{item.name}</h3>
                        <p>Director</p>
                      </div>
                    </div>
                  ))}
              </div>
              <div className="col-lg-5 col-md-12 text-center">
                {data
                  .filter((item) => item.category === "Director")
                  .map((item, index) => (
                    <img
                      key={index}
                      src={getImageUrl(
                        item,
                        "https://via.placeholder.com/400x400?text=Director"
                      )}
                      className="img-fluid"
                      alt="Director"
                    />
                  ))}
              </div>
            </div>
            <Link to="/director-message">Read More</Link>
          </Carousel.Item>

          {/* Principal */}
          <Carousel.Item>
            <div className="row msg align-items-center">
              <div className="col-lg-7 col-md-12">
                {data
                  .filter((item) => item.category === "Principal")
                  .map((item, index) => (
                    <div key={index}>
                      <p>{stripHtmlTags(item.message)}</p>
                      <div className="clr"></div>
                      <div className="name-board">
                        <h3>{item.name}</h3>
                        <p>Principal</p>
                      </div>
                    </div>
                  ))}
              </div>
              <div className="col-lg-5 col-md-12 text-center">
                {data
                  .filter((item) => item.category === "Principal")
                  .map((item, index) => (
                    <img
                      key={index}
                      src={getImageUrl(
                        item,
                        "https://via.placeholder.com/400x400?text=Principal"
                      )}
                      className="img-fluid"
                      alt="Principal"
                    />
                  ))}
              </div>
            </div>
            <Link to="/principal-message">Read More</Link>
          </Carousel.Item>
        </Carousel>
      </div>
    </div>
  );
}

export default Homemesdesk;

