import { useEffect, useState } from "react";
import MissionVision from "./MissionVision";
import { getPrincipalMessage } from "../Service/Api";

function HomeMessage() {
  const [deskMessages, setDeskMessages] = useState([]);

  useEffect(() => {
    async function fetchData() {
      try {
        const res = await getPrincipalMessage();

        // API returns array directly
        if (Array.isArray(res)) {
          setDeskMessages(res);
        }
      } catch (error) {
        console.error("API Error:", error);
      }
    }

    fetchData();
  }, []);

  return (
    <section className="mesdesk">
      <div className="custom-padding">
        <div className="row">
          <div className="col-12">
            <h4 className="subhead">From the</h4>
            <h2 className="mainheadbg">desk of</h2>
          </div>

          <div className="col-xl-6">
            {deskMessages.length > 0 && (
              <div
                id="deskCarousel"
                className="carousel slide"
                data-bs-ride="carousel"
              >
                <div className="carousel-inner">
                  {deskMessages.map((item, index) => (
                    <div
                      key={item._id}
                      className={`carousel-item ${index === 0 ? "active" : ""}`}
                    >
                      <div className="Mesdeskarea">
                        {/* Image */}
                        <div className="Mesdeskarea-Img">
                          <img
                            src={`https://webapi.entab.info/api/image/${item.attachments?.[0]}`}
                            className="img-fluid"
                            alt={item.name}
                          />
                        </div>

                        {/* Text */}
                        <div className="Mesdeskarea-Text">
                          <img
                            src="/images/quotesTop.svg"
                            className="img-fluid"
                            alt="quotes"
                          />

                          <p>
                            {item.message?.replace(/\r?\n|\r/g, " ")?.trim()}
                          </p>

                          <div className="text-end">
                            <img
                              src="/images/quotesTop.svg"
                              className="img-fluid"
                              alt="quotes"
                            />
                          </div>

                          <h4>{item.name}</h4>
                          <h5>{item.category}</h5>

                          <div className="viewmorebtn">
                            <a href="#">Read More</a>
                          </div>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>

                {/* Controls */}

                <div className="message_ctrl_btn">
                  <button
                    className="carousel-control-prev"
                    type="button"
                    data-bs-target="#deskCarousel"
                    data-bs-slide="prev"
                  >
                    <span className="carousel-control-prev-icon">
                      <i className="bi bi-caret-left-fill"></i>
                    </span>
                  </button>

                  <button
                    className="carousel-control-next"
                    type="button"
                    data-bs-target="#deskCarousel"
                    data-bs-slide="next"
                  >
                    <span className="carousel-control-next-icon">
                      <i className="bi bi-caret-right-fill"></i>
                    </span>
                  </button>
                </div>
              </div>
            )}
          </div>

          <div className="col-xl-6">
            <MissionVision />
          </div>
        </div>
      </div>
    </section>
  );
}

export default HomeMessage;

