import React, { useRef } from "react";
import { Link } from "react-router-dom";

function HomeNews() {
  const marqueeRef = useRef(null);

  const handleMouseOver = () => {
    marqueeRef.current?.stop();
  };

  const handleMouseOut = () => {
    marqueeRef.current?.start();
  };

  const events = [
    {
      title: "Annual Sports Meet",
      description: "Inter-school sports competition for all grades.",
      date: "12 Dec 2025",
      attachment: "#",
    },
    {
      title: "Parent Teacher Meeting",
      description: "Discussion on academic progress and activities.",
      date: "18 Dec 2025",
      attachment: "#",
    },
    {
      title: "Winter Vacation Notice",
      description: "School will remain closed for winter holidays.",
      date: "22 Dec 2025",
      attachment: "#",
    },
  ];

  return (
    <div className="EventsSec">
      <h4 className="subhead white">Events</h4>
      <h2 className="mainhead">Important Notice</h2>
      <br />

      {/* ✅ Marquee retained */}
      <marquee
        direction="up"
        ref={marqueeRef}
        onMouseOver={handleMouseOver}
        onMouseOut={handleMouseOut}
      >
        {events.map((event, index) => (
          <div className="event-content" key={index}>
            <div className="left-arrow">
              <img src="/images/arrow.webp" className="img-fluid" alt="arrow" />
            </div>

            <div className="middle-info">
              <h3 className="event-title">{event.title}</h3>
              <p className="event-desc">{event.description}</p>
              <span className="event-date">{event.date}</span>
            </div>

            <div className="right-attach">
              <a href={event.attachment}>
                <img
                  src="/images/atta.webp"
                  className="img-fluid"
                  alt="attachment"
                />
              </a>
            </div>
          </div>
        ))}
      </marquee>

      <br />

      <div className="viewmore">
        <Link to="/news">View More</Link>
      </div>
    </div>
  );
}

export default HomeNews;

