import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import Carousel from 'react-bootstrap/Carousel';
import { getTestimonials } from '../Service/Api';
import { API_URL } from '../config';
import LazyLoad from 'react-lazyload';

function HomeTestimonials() {
  const [data, setData] = useState([]);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const response = await getTestimonials();
        // Assuming response is an array of testimonial objects with a 'createdAt' field
        const sortedData = response.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
        setData(sortedData);
      } catch (error) {
        console.error('Error fetching testimonials:', error);
      }
    };
    fetchData();
  }, []);

  return (
    <div className="col-xxl-5 col-xl-5 col-lg-12 col-md-12 col-sm-12">
      <h5 className="animate-charcter-colr">Stakeholders Speak</h5>
      <h1 data-aos-duration="2000" data-aos="fade-right">
        Testimonials <Link to="/testimonials"><i className="bi bi-arrow-bar-right"></i></Link>
      </h1>
      <div className='row'>
        <div className="col-xxl-12 col-lg-12 col-md-12 col-sm-12">
          <Carousel>
            {data.map((item, index) => (
              <Carousel.Item key={index}>
                <div className='Testimonials-Box'>
                  <article>
                    <p>
                     <img src={`${API_URL}/api/image?url=${item.attachments[0]}`} className="img-fluid" alt="Testimonial" /> 
                      {new DOMParser().parseFromString(item.description, "text/html").body.textContent}

                    </p>
                    <div className="attachment">{item.name}</div>
                  </article>
                </div>
              </Carousel.Item>
            ))}
          </Carousel>
        </div>
      </div>
    </div>
  );
}

export default HomeTestimonials;

