import React from "react";
import { Link } from "react-router-dom";
import CustomBtn from "../utlis/CustomBtn";

function HomeVideoGallery() {
  // Hardcoded video data
  const video = {
    title: "Sample Video",
    videoUrl: "https://youtu.be/o30saej7cwc",
  };

  // Function to convert YouTube URL to embed URL
  const getEmbedUrl = (url) => {
    if (!url) return "";
    const videoIdMatch = url.match(
      /(?:youtu\.be\/|youtube\.com\/watch\?v=|youtube\.com\/embed\/)([^?&]+)/
    );
    const videoId = videoIdMatch ? videoIdMatch[1] : null;
    return videoId ? `https://www.youtube.com/embed/${videoId}` : url;
  };

  return (
    <div className="home_video_jsx">
      <div className="home_video_title">
        <h5 className="subhead">Video Gallery</h5>
        <h2>Memories in Motion</h2>
      </div>
      <div className="row">
        <div className="col">
          <iframe
            width="100%"
            height="230"
            src={getEmbedUrl(video.videoUrl)}
            title={video.title}
            frameBorder="0"
            allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share"
            referrerPolicy="strict-origin-when-cross-origin"
            allowFullScreen
          ></iframe>
        </div>

        <div className="galbtn">
          <CustomBtn extraClass="description-btn" LinkTo="video-gallery">
            View All
          </CustomBtn>
        </div>
      </div>
    </div>
  );
}

export default HomeVideoGallery;

