import React, { useState, useEffect } from "react";
import { getNotification } from "../Service/Api";
import { Link } from "react-router-dom";

function ModalPopup() {
  const [data, setData] = useState([]);
  const [showModal, setShowModal] = useState(false);

  const hideModal = () => {
    const modalElement = document.getElementById("exampleModalToggle");
    if (modalElement) {
      modalElement.classList.remove("show");
      modalElement.style.display = "none";
    }
  };

  useEffect(() => {
    const getData = async () => {
      const datas = await getNotification();
      console.log(datas);
      setData(datas);
    };
    getData();
  }, []);

  useEffect(() => {
    const modalElement = document.getElementById("exampleModalToggle");
    if (modalElement) {
      modalElement.classList.add("show");
      modalElement.style.display = "block";

      document.querySelectorAll(".btn-close-white").forEach((btn) => {
        btn.addEventListener("click", () => {
          modalElement.classList.remove("show");
          modalElement.style.display = "none";
        });
      });
    }

    // Cleanup event listeners on unmount or when data changes
    return () => {
      if (modalElement) {
        document.querySelectorAll(".btn-close-white").forEach((btn) => {
          btn.removeEventListener("click", () => {});
        });
      }
    };
  }, [data]);

  const handleModalHidden = () => {
    const modalBackdrop = document.getElementsByClassName("modal-backdrop")[0];
    if (modalBackdrop) {
      modalBackdrop.parentNode.removeChild(modalBackdrop);
    }
  };

  return (
    <>
      {data?.length > 0 && (
        <div
          className="modal fade"
          id="exampleModalToggle"
          aria-hidden="true"
          aria-labelledby="exampleModalToggleLabel"
          tabIndex="-1"
          style={{ display: "none" }}
          onClick={(event) => {
            if (event.target === event.currentTarget) {
              hideModal();
            }
          }}
        >
          <div
            className="modal-dialog modal-dialog-centered"
            onClick={(event) => event.stopPropagation()}
          >
            <div className="modal-content">
              <div
                id="modalH"
                className="carousel slide"
                data-bs-ride="carousel"
              >
                <div className="carousel-inner">
                  {data.map((item, index) => (
                    <div
                      key={index}
                      className={`carousel-item${index === 0 ? " active" : ""}`}
                    >
                      <div className="modal-header">
                        <h1>{item.title}</h1>
                        <button
                          type="button"
                          className="btn-close btn-close-white"
                          data-bs-dismiss="modal"
                          aria-label="Close"
                          onClick={hideModal}
                        ></button>
                      </div>
                      <div className="modal-body">
                        <div className="card modalcard">
                          <div className="row">
                            <div className="card-body">
                              {item.image && item.image.length > 0 && (
                                <img
                                  src={`https://webapi.entab.info/api/image/${item.image[0]}`}
                                  className="img-fluid"
                                  alt="DPS School, Hyderabad"
                                />
                              )}
                              <p>{item.description}</p>
                              <div className="clearfix"></div>
                              <br />
                              <div className="d-grid gap-2 d-md-flex justify-content-around d-block mx">
                                {item.attachments &&
                                  item.attachments.length > 0 && (
                                    <Link
                                      target="_blank"
                                      to={`https://webapi.entab.info/api/image/${item.attachments[0]}`}
                                      className="btn btn-warning btn-sm"
                                    >
                                      Attachment
                                    </Link>
                                  )}
                                {item.url && item.url.trim() !== "" && (
                                  <Link
                                    target="_blank"
                                    to={item.url}
                                    className="btn btn-warning btn-sm"
                                  >
                                    Click Here
                                  </Link>
                                )}
                              </div>
                            </div>
                          </div>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
                <button
                  className="carousel-control-prev"
                  type="button"
                  data-bs-target="#modalH"
                  data-bs-slide="prev"
                >
                  <span
                    className="carousel-control-prev-icon"
                    aria-hidden="true"
                  ></span>
                  <span className="visually-hidden">Previous</span>
                </button>
                <button
                  className="carousel-control-next"
                  type="button"
                  data-bs-target="#modalH"
                  data-bs-slide="next"
                >
                  <span
                    className="carousel-control-next-icon"
                    aria-hidden="true"
                  ></span>
                  <span className="visually-hidden">Next</span>
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </>
  );
}

export default ModalPopup;

