import React, { useEffect, useRef } from 'react';
function Foundressmes() {

    const headingRef = useRef(null);

    useEffect(() => {
        const element = headingRef.current;

        const observer = new IntersectionObserver(
            ([entry]) => {
                if (entry.isIntersecting) {
                    element.classList.remove("typing");
                    void element.offsetWidth; // reset animation
                    element.classList.add("typing");
                } else {
                    element.classList.remove("typing");
                }
            },
            { threshold: 0.1 }
        );

        observer.observe(element);

        return () => observer.disconnect();
    }, []);

    return (
        <div className='Foundressmes'>
            <h3 ref={headingRef} className="mb-3 typewriter">
                She Lit The Path..
            </h3>
            <p className='FoundressmesText' >
                Mater Dei School for girls, was established in 1956, by the Sisters, Franciscan Missionaries of Mary. This Christian Minority School was begun with the primary objective of providing education in a Christian atmosphere to all children, especially Christians. Our aim is personal and integral formation of the young. We make special efforts towards the moral, spiritual, intellectual, social and physical development of children. The motto of our school is “To love through Truth’. Mater Dei School for girls, was established in 1956, by the Sisters, Franciscan Missionaries of Mary. This Christian Minority School was begun with the primary objective of providing education in a Christian atmosphere to all children, especially Christians. Our aim is personal and integral formation of the young. We make special efforts towards the moral, spiritual, intellectual, social and physical development of children.
            </p>
            <a href="/mother-foundress" className="btn btn-dark read-more-btn">
                Read more
                <img src="https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/DEMO7/public/images/arrow-up.svg" alt="materdeischool" className="arrow-up img-fluid" />
            </a>
        </div>
    );
}

export default Foundressmes;

