import React, { useState, useEffect } from 'react';
function Goto() {
  const [visible, setVisible] = useState(false);

  // Show button only when user scrolls down
  useEffect(() => {
    const handleScroll = () => {
      if (window.scrollY > 300) { // show after 300px scroll
        setVisible(true);
      } else {
        setVisible(false);
      }
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Scroll to top function
  const scrollToTop = () => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    visible && (
      <div className="Goto" onClick={scrollToTop}>
        <img
          src="https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/DEMO7/public/images/goto.png"
          alt="materdeischool"
          className="img-fluid"
        />
      </div>
    )
  );
}

export default Goto;

