import React, { useState, useEffect } from 'react';
import { getEvents } from "../Service/Api"; // Assuming the getEvents API fetches the events

function HomeEvents() {
    const [eventsData, setEventsData] = useState([]); // State to hold fetched events data

    // Static fallback data for when the API fails or returns no data
    const staticEventsData = [
        { id: 1, title: "Shivaji Jayanti", date: "19 Feb 2026", images: ["https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/DEMO7/public/images/event1.jpg"] },
        { id: 2, title: "Holika Dahan", date: "03 March 2026", images: ["https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/DEMO7/public/images/event2.jpg"] },
        { id: 3, title: "Holi", date: "04 March 2026", images: ["https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/DEMO7/public/images/event3.jpg"] },
        { id: 4, title: "International Women's Day", date: "08 March 2026", images: ["https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/DEMO7/public/images/event4.jpg"] },
    ];

    // Fetch events data from the API
    useEffect(() => {
        const fetchEvents = async () => {
            try {
                const data = await getEvents(); // Fetch the events data from the API
                setEventsData(data || []); // Set the fetched data or empty array
            } catch (error) {
                console.error("Error fetching events:", error);
                setEventsData([]); // Set empty array in case of error
            }
        };
        fetchEvents();
    }, []); // Only run once when the component mounts

    // Use static data if no events data is available from the API
    const displayEvents = eventsData.length > 0 ? eventsData.slice(0, 4) : staticEventsData;

    return (
        <>
            <div className='row'>
                {/* First event on the left side */}
                {displayEvents.slice(0, 1).map((item) => (
                    <div className='col-lg-6 col-md-12' data-aos="zoom-in" data-aos-duration="1500" data-aos-once="false" key={item.id}>
                        <div className='event-box'>
                            <div className='img-zoom'>
                                <img
                                    src={
                                        item.images && item.images.length > 0
                                            ? `https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/${item.images[0]}`
                                            : "https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/MTRTD/public/Images/events.jpg"
                                    }
                                    alt={item.title}
                                    className="event-img"
                                />
                            </div>
                            <div className='event-details mt-3'>
                                <p className='event-date'>{item.date}</p>
                                <h5 className='event-title'>{item.title}</h5>
                            </div>
                        </div>
                    </div>
                ))}

                {/* Next three events on the right side */}
                <div className='col-lg-6 col-md-12' data-aos="fade-left" data-aos-duration="1500" data-aos-once="false">
                    {displayEvents.slice(1).map((item, index) => (
                        <div key={item.id}>
                            <div className='event-box-small d-flex'>
                                <div className='event-details'>
                                    <p className='event-date'>{item.date}</p>
                                    <h5 className='event-title'>{item.title}</h5>
                                </div>
                                <div className='event-details-img'>
                                    <img
                                        src={item.images && item.images.length > 0 ? `https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/${item.images[0]}` : item.image}
                                        alt={item.title}
                                        className='event-img mx-auto d0block'
                                    />
                                </div>
                            </div>

                            {/* Add divider only if it's not the last event */}
                            {index !== displayEvents.slice(1).length - 1 && <hr className='event-divider' />}
                        </div>
                    ))}
                </div>
            </div>
        </>
    );
}

export default HomeEvents;

