function HomeNews() {
    const [newsData, setNewsData] = useState([]); // State to hold fetched news data

    // Static fallback data when no dynamic data is fetched
    const staticNewsData = [
        {
            _id: "1",
            title: "Spanish Fest and Carol Singing Competition (VI-VII)",
            fromDate: "2026-02-20",
        },
        {
            _id: "2",
            title: "Annual Science Exhibition",
            fromDate: "2026-02-25",
        },
        {
            _id: "3",
            title: "Inter-School Sports Day",
            fromDate: "2026-03-01",
        }
    ];

    // Fetch news data on component mount
    useEffect(() => {
        const fetchNews = async () => {
            try {
                const data = await getNews(); // Fetch news data from API
                setNewsData(data || []); // Set news data to state, fallback to empty array if no data
            } catch (error) {
                console.error("Error fetching news:", error);
                setNewsData([]); // Set empty array in case of error
            }
        };

        fetchNews(); // Call the fetch function
    }, []); // Empty dependency array ensures this runs only once when the component mounts

    // Format date using Intl API with abbreviated month names
    const formatDate = (dateStr) => {
        try {
            const date = new Date(dateStr);
            const monthNames = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];

            // Pad day with leading zero if necessary
            const day = String(date.getDate()).padStart(2, '0');
            const month = monthNames[date.getMonth()]; // Use abbreviated month
            const year = date.getFullYear();

            return `${day} ${month} ${year}`.toUpperCase();
        } catch {
            return "";
        }
    };

    // Slider settings for the news section
    const settings = {
        dots: false,
        infinite: true,
        arrows: false,
        speed: 3000,
        slidesToShow: 3,
        slidesToScroll: 1,
        autoplay: true,
        autoplaySpeed: 4000,
        cssEase: "ease-in-out",
        responsive: [
            {
                breakpoint: 1599,
                settings: { slidesToShow: 2, slidesToScroll: 1 },
            },
            {
                breakpoint: 991,
                settings: { slidesToShow: 2, slidesToScroll: 1 },
            },
            {
                breakpoint: 767,
                settings: { slidesToShow: 1, slidesToScroll: 1 },
            },
        ],
    };

    // Use static data if no news data is available from the API
    const displayNews = newsData.length > 0 ? newsData : staticNewsData;

    return (
        <div className="row">
            <Slider {...settings}>
                {displayNews.length > 0 ? (
                    displayNews.map((item) => {
                        const formattedDate = formatDate(item.fromDate).split(' ');
                        return (
                            <div className="NewBox" key={item._id} data-aos="zoom-in" data-aos-duration="1500" data-aos-once="false">
                                <div className="date">
                                    <h3>{formattedDate[0]}</h3>
                                    <h6>{formattedDate.slice(1).join(' ')}</h6>
                                </div>
                                <div className="NewText">
                                    <p>{item.title}</p>
                                </div>
                            </div>
                        );
                    })
                ) : (
                    <div className="NewBox">
                        <p>No news available at the moment.</p>
                    </div>
                )}
            </Slider>
        </div>
    );
}

export default HomeNews;

