import React, { useEffect, useState } from "react";
import { getOnlineRegistration } from "../Service/Api";
import LazyLoad from "react-lazyload";
function OnlineRegistration() {
    const [data, setData] = useState([]);
    useEffect(() => {
        const fetchData = async () => {
            try {
                const data = await getOnlineRegistration();
                setData(data);
            } catch (error) {
                console.error("Error fetching online registration data:", error);
            }
        };
        fetchData();
    }, []);

    return (
        <>
            {data.length > 0 ? (
                data.map((item, index) => (
                    <div key={index} className="online-reg">
                        <a
                            href={item.url}
                            target="_blank"
                            rel="noopener noreferrer"
                        >
                            {/* <LazyLoad> <img 
                                src="https://webapi.entab.info/api/image/DPSH/public/online-reg.gif" 
                                className="img-fluid" 
                                alt="DPS Hyderabad" 
                            /></LazyLoad>  */}
                            {item.title}
                        </a>
                        {item.attachments.length > 0 ? (
                            <a
                                href={`https://webapi.entab.info/api/image/${item.attachments[0]}`}
                                target="_blank"
                                rel="noopener noreferrer"
                            >
                                <i className="bi bi-paperclip"></i>
                            </a>
                        ) : <></>}
                    </div>
                ))
            ) : (
                <div></div>
            )}
        </>
    )
}

export default OnlineRegistration

