import React, { useEffect, useState } from "react";
import Slider from "react-slick";
import "slick-carousel/slick/slick.css";
import "slick-carousel/slick/slick-theme.css";
import { getBirthdays } from "../Service/Api"; // your API function

function BirthDay() {
  const [birthdays, setBirthdays] = useState([]);

  useEffect(() => {
    const fetchBirthdays = async () => {
      try {
        const data = await getBirthdays();
        let mappedBirthdays = [];

        if (data && data.length > 0) {
          mappedBirthdays = data.map((item) => ({
            image: item?.attachments?.[0]
              ? `https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/${item.attachments[0]}`
              : "https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/DEMO9/public/images/birthday-placeholder.jpg",
            date: item?.date
              ? new Date(item.date).toLocaleDateString("en-GB", {
                  day: "2-digit",
                  month: "short",
                })
              : "",
            name: item?.name || "Student",
            className: item?.class || "",
          }));
        }

        // fallback dummy items if API returns empty
        if (mappedBirthdays.length === 0) {
          mappedBirthdays = Array.from({ length: 2 }, () => ({
            image:
              "https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/DEMO9/public/images/principle-d.jpg",
            date: "",
            name: "Student",
            className: "",
          }));
        }

        setBirthdays(mappedBirthdays);
      } catch (error) {
        console.error("Error fetching birthdays:", error);
        setBirthdays(
          Array.from({ length: 2 }, () => ({
            image:
              "https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/DEMO9/public/images/birthday-placeholder.jpg",
            date: "",
            name: "Student",
            className: "",
          })),
        );
      }
    };

    fetchBirthdays();
  }, []);

  const settings = {
    dots: false,
    infinite: true,
    speed: 500,
    slidesToShow: 2,
    slidesToScroll: 1,
    autoplay: true,
    autoplaySpeed: 2000,
    cssEase: "linear",
    responsive: [
      { breakpoint: 1599, settings: { slidesToShow: 1, slidesToScroll: 1 } },
      { breakpoint: 991, settings: { slidesToShow: 2, slidesToScroll: 1 } },
      { breakpoint: 600, settings: { slidesToShow: 1, slidesToScroll: 1 } },
      { breakpoint: 480, settings: { slidesToShow: 1, slidesToScroll: 1 } },
    ],
  };

  return (
    <div className="col-xl-4 col-lg-4 col-md-12 Birthday">
      <div className="col-12">
        <h3 className="section-subtitle">Stars of the day</h3>
        <h2 className="section-title">Birthday Section</h2>
      </div>

      <div className="row">
        <Slider {...settings}>
          {birthdays.map((birthday, index) => (
            <div className="BirthdaySec" key={index}>
              <div className="birthday-img-wrapper">
                <img
                  src="https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/DEMO9/public/images/birthday-vector.png"
                  className="birthday-hover-img"
                  alt="Birthday"
                />
                <div className="birthday-border">
                  <img
                    src={birthday.image}
