              </div>
              <div className="birthday-info">
                <h3 className="birthday-score">{birthday.date}</h3>
                <h4>{birthday.name}</h4>
                <h5>{birthday.className}</h5>
              </div>
            </div>
          ))}
        </Slider>
      </div>
    </div>
  );
}

export default BirthDay;

