import React, { useState, useEffect } from "react";
import { getEventsinner } from "../Service/Api";

function Calendar() {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [monthEvents, setMonthEvents] = useState([]);
  const [data, setData] = useState([]);

  // Fetch events from API
  useEffect(() => {
    const getData = async () => {
      try {
        const datas = await getEventsinner();
        if (datas && datas.length > 0) {
          setData(datas);
        }
      } catch (error) {
        console.error("Error fetching events data:", error);
      }
    };
    getData();
  }, []);

  // Group events by day of the current month
  useEffect(() => {
    if (data.length > 0) {
      const grouped = {};
      data.forEach((event) => {
        const eventDate = new Date(event.date);
        if (
          eventDate.getMonth() === currentDate.getMonth() &&
          eventDate.getFullYear() === currentDate.getFullYear()
        ) {
          const day = eventDate.getDate();
          if (!grouped[day]) grouped[day] = [];
          grouped[day].push({
            title: event.title,
            attachments: event.attachments,
          });
        }
      });

      const monthEventsData = Object.entries(grouped)
        .map(([day, events]) => ({ day: parseInt(day), events }))
        .sort((a, b) => a.day - b.day);

      setMonthEvents(monthEventsData);
    } else {
      setMonthEvents([]);
    }
  }, [data, currentDate]);

  // Change month
  const changeMonth = (direction) => {
    const newDate = new Date(currentDate);
    newDate.setMonth(newDate.getMonth() + direction);
    setCurrentDate(newDate);
  };

  // Check if day has event
  const dayHasEvent = (day) => monthEvents.some((e) => e.day === day);

  // Check if day is today
  const isToday = (day) => {
    const today = new Date();
    return (
      day === today.getDate() &&
      currentDate.getMonth() === today.getMonth() &&
      currentDate.getFullYear() === today.getFullYear()
    );
  };

  // Handle day click
  const handleDayClick = (day) => {
    const events = monthEvents.find((e) => e.day === day)?.events || [];
    if (events.length === 0) {
      alert(`No events on ${day}`);
    } else {
      alert(`Events on ${day}:\n${events.map((ev) => ev.title).join("\n")}`);
    }
  };

  // Render calendar days
  const renderCalendarDays = () => {
    const firstDayOfMonth = new Date(
      currentDate.getFullYear(),
      currentDate.getMonth(),
      1,
    );
    const lastDayOfMonth = new Date(
      currentDate.getFullYear(),
      currentDate.getMonth() + 1,
      0,
    );
    const daysInMonth = Array.from(
      { length: lastDayOfMonth.getDate() },
      (_, i) => i + 1,
    );
    const startDay = firstDayOfMonth.getDay();
    const blankDays = Array.from({ length: startDay }, (_, i) => i);

    return (
      <>
        {blankDays.map((_, index) => (
          <div key={`blank-${index}`} className="col-cal blank-day"></div>
        ))}
        {daysInMonth.map((day) => (
          <div
            key={day}
            className={`col-cal day ${dayHasEvent(day) ? "active-day" : ""} ${isToday(day) ? "today" : ""}`}
            onClick={() => handleDayClick(day)}
          >
            {day}
            {dayHasEvent(day) && <span className="day-event">•</span>}
          </div>
        ))}
      </>
    );
  };

  const monthName = currentDate.toLocaleString("en-US", { month: "long" });
  const yearNum = currentDate.getFullYear();

  return (
    <div className="event-cal">
      <h6 className="section-subtitle">The Year at a Glance</h6>
      <h2 className="section-title">Academic calendar</h2>
      <div className="calendar-wrapper">
        {/* Header */}
        <div className="calendar-header">
          <button className="prev-button" onClick={() => changeMonth(-1)}>
            &#8592;
          </button>
          <h3>{`${monthName} ${yearNum}`}</h3>
          <button className="next-button" onClick={() => changeMonth(1)}>
            &#8594;
          </button>
        </div>

        {/* Calendar grid */}
        <div className="calendar-grid">
          <div className="row header">
            {["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"].map((d) => (
              <div key={d} className="col-cal day-name">
                {d}
              </div>
            ))}
          </div>
          <div className="row days">{renderCalendarDays()}</div>
        </div>

        {/* Footer events */}
        <div className="calendar-footer">
          {monthEvents.length === 0 ? (
            <div className="text-center">
              <img
                src="https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/DEMO9/public/images/dummy.jpg"
                alt=""
              />
            </div>
          ) : (
            monthEvents.map((dayGroup) =>
              dayGroup.events.map((ev, i) => (
                <p key={i}>
                  <strong>{dayGroup.day}:</strong> {ev.title || ""}
                </p>
              )),
            )
          )}
        </div>
      </div>
    </div>
  );
}

export default Calendar;

