import React, { useEffect, useState } from "react";
import Slider from "react-slick";
import { Link } from "react-router-dom";
import { getGallery } from "../Service/Api";

function HomeGallery() {
  const [galleryData, setGalleryData] = useState([]);
  const sliderSettings = {
    dots: false,
    arrows: false,
    infinite: galleryData.length > 3,
    speed: 500,
    slidesToShow: 3,
    slidesToScroll: 1,
    responsive: [
      {
        breakpoint: 992,
        settings: {
          slidesToShow: 2,
          slidesToScroll: 1,
        },
      },
      {
        breakpoint: 768,
        settings: {
          slidesToShow: 1,
          slidesToScroll: 1,
        },
      },
    ],
  };

  useEffect(() => {
    const fetchGallery = async () => {
      try {
        const data = await getGallery();
        if (data && data.length > 0) {
          setGalleryData(data);
        }
      } catch (error) {
        console.error("Error fetching gallery data:", error);
      }
    };
    fetchGallery();
  }, []);

  return (
    <>
      <div className="row">
        <div className="col-12">
          <img
            src="https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/DEMO9/public/images/video-channel.gif"
            className="img-fluid mx-auto d-block video-channel"
            alt="st xavier kolkata"
          />
          <h3 className="section-subtitle">memories in media</h3>
          <h2 className="section-title">gallery section</h2>
        </div>
      </div>

      <div className="container-fluid-landing">
        <div className="row g-3">
          {galleryData.length > 0 ? (
            <Slider {...sliderSettings}>
              {galleryData
                .sort(
                  (a, b) =>
                    (new Date(b?.date).getTime() || 0) -
                    (new Date(a?.date).getTime() || 0)
                )
                .slice(0, 3)
                .map((item, index) => (
                <div key={index} className="px-2">
                  <div className="HomeGallery">
                    <div className="gal-img-wrapper">
                      <img
                        src={
                          item?.attachments?.[0]
                            ? `https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/${item.attachments[0]}`
                            : "https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/DEMO9/public/images/dummy.jpg"
                        }
                        className="img-fluid"
                        alt={item?.title || ""}
                      />
                      <div className="overlay">
                        <p
                          dangerouslySetInnerHTML={{
                            __html: item?.title || "",
                          }}
                        />
                      </div>
                    </div>
                  </div>
                </div>
              ))}
            </Slider>
          ) : (
            <div className="col-12 text-center">
              <img
                src="https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/DEMO9/public/images/dummy.jpg"
                alt=""
              />
            </div>
          )}
        </div>
      </div>

      <div className="row">
        <div className="col-12 pt-5">
          <center>
            <a className="thm-btn" href="/photogallery">
              View All <i className="bi bi-arrow-right-short"></i>
            </a>
          </center>
        </div>
      </div>
    </>
  );
}

export default HomeGallery;

