                    )}

                    {/* Render title and description */}
                    <span
                      dangerouslySetInnerHTML={{
                        __html: ` ${item.description}`,
                      }}
                    />

                    {index < highlights.length - 1 && (
                      <span className="separator">|</span>
                    )}
                  </React.Fragment>
                ))
              ) : (
                <span
                  dangerouslySetInnerHTML={{
                    __html: "Stay tuned for latest updates",
                  }}
