        const data = await getEvents();
        if (data && data.length > 0) {
          setEventsData(data);
        }
      } catch (error) {
        console.error("Error fetching events data:", error);
      }
    };
    fetchEvents();
  }, []);

  const formatDate = (dateString) => {
    const date = new Date(dateString);
    return date.toLocaleString("en-US", { day: "2-digit", month: "short" });
  };

  const settings = {
    dots: false,
    infinite: true,
    speed: 500,
    slidesToShow: 4,
    slidesToScroll: 1,
    autoplay: true,
    autoplaySpeed: 2000,
    cssEase: "linear",
    responsive: [
      { breakpoint: 1599, settings: { slidesToShow: 3, slidesToScroll: 1 } },
      { breakpoint: 991, settings: { slidesToShow: 2, slidesToScroll: 1 } },
      { breakpoint: 600, settings: { slidesToShow: 1, slidesToScroll: 1 } },
      { breakpoint: 480, settings: { slidesToShow: 1, slidesToScroll: 1 } },
    ],
  };

  return (
    <>
      <section className="EventSec">
        {eventsData.length > 0 ? (
          <Slider {...settings}>
            {eventsData.map((item, index) => (
              <div className="EventBox" key={index}>
                <div
                  className="event-loc"
                  dangerouslySetInnerHTML={{
                    __html: item?.venue || "",
                  }}
                />

                <img
                  src={
                    item?.images?.[0]
                      ? `https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/${item.images[0]}`
                      : "https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/DEMO9/public/images/dummy.jpg"
                  }
                  className="img-fluid"
                  alt="St. Xavier"
                />

                <h3
                  dangerouslySetInnerHTML={{
                    __html: item?.title || "",
                  }}
                />

                <div>
                  <h6 className="date-time">
                    <span
                      className="date-block"
                      dangerouslySetInnerHTML={{
                        __html: item?.date
                          ? `<i class="bi bi-calendar"></i> ${formatDate(item.date)}`
                          : "",
                      }}
                    />
                    <span
                      className="time-block"
                      dangerouslySetInnerHTML={{
                        __html: item?.time || "",
                      }}
                    />
                  </h6>
                </div>
              </div>
            ))}
          </Slider>
        ) : (
          <div className="col-12 text-center">
            <img
              src="https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/DEMO9/public/images/dummy.jpg"
              alt=""
            />
          </div>
        )}

        <div className="row">
          <div className="col-12 pt-5">
            <center>
              <a className="thm-btn" href="/events">
                View All <i className="bi bi-arrow-right"></i>
              </a>
            </center>
          </div>
        </div>
      </section>
    </>
  );
}

export default HomeEvents;

