import React, { useEffect, useState } from "react";
import { getPrincipalMessage } from "../Service/Api";

// ✅ Default fallback
const defaultPrincipal = {
  image:
    "https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/DEMO9/public/images/principle-d.jpg",
  name: "Principal Name",
  designation: "Principal",
};

function MesDesk() {
  const [principalData, setPrincipalData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchPrincipalMessage = async () => {
      try {
        const data = await getPrincipalMessage();
        if (data && data.length > 0) {
          setPrincipalData(data[0]);
        }
      } catch (error) {
        console.error("Error fetching principal message:", error);
      } finally {
        setLoading(false);
      }
    };
    fetchPrincipalMessage();
  }, []);

  // ✅ Prevent glitch when data is loading
  if (loading) {
    return <div className="homemes">Loading...</div>;
  }

  const imageUrl =
    principalData?.attachments?.length > 0
      ? `https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/${principalData.attachments[0]}`
      : defaultPrincipal.image;

  return (
    <div className="homemes">
      <h6 className="section-subtitle">From the desk of</h6>
      <h2 className="section-title">Principal message</h2>

      <div className="MesDesk">
        <div className="MesDeskImg">
          <img
            src={imageUrl}
            onError={(e) => {
              // ✅ Prevent infinite loop glitch
              if (
                e.target.src !==
                window.location.origin + defaultPrincipal.image
              ) {
                e.target.src = defaultPrincipal.image;
              }
            }}
            className="img-fluid"
            alt={principalData?.name || "Principal"}
          />

          <h4>{principalData?.name || defaultPrincipal.name}</h4>
          <h6>{principalData?.designation || defaultPrincipal.designation}</h6>
        </div>

        <div className="MesDeskMes">
          <div className="quotes-wrapper">
            {principalData?.message ? (
              <p
                className="desk-text"
                dangerouslySetInnerHTML={{
                  __html: principalData.message,
                }}
              />
            ) : (
              <p className="desk-text">No message available</p>
            )}
          </div>

          <div className="buttonarea">
            <img
              src="https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/DEMO9/public/images/quotesbot.png"
              className="quote-icon bottom"
              alt="quotes"
            />

            <a href="/principal-message" className="read-more-btn">
              View All <i className="bi bi-arrow-right"></i>
            </a>

            <img
              src="https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/DEMO9/public/images/sent.png"
              className="img-fluid sent-icon"
              alt="sent icon"
            />
          </div>
        </div>
      </div>
    </div>
  );
}

export default MesDesk;

