import React, { useState, useEffect, useRef } from "react";
import { getNews } from "../Service/Api";

function NoticeBoard() {
  const [newsData, setNewsData] = useState([]);
  const [paused, setPaused] = useState(false);
  const containerRef = useRef(null);

  useEffect(() => {
    const fetchNews = async () => {
      try {
        const data = await getNews();
        if (data && data.length > 0) setNewsData(data);
      } catch (error) {
        console.error("Error fetching news:", error);
      }
    };
    fetchNews();
  }, []);

  return (
    <>
      <ul className="bulletin-list">
        <h6>Our School Notices</h6>
        <h2>Notice Board</h2>

        <div
          className="marquee-wrapper"
          onMouseEnter={() => setPaused(true)}
          onMouseLeave={() => setPaused(false)}
        >
          <div
            ref={containerRef}
            className="marquee-content"
            style={{ animationPlayState: paused ? "paused" : "running" }}
          >
            {(newsData.length > 0
              ? newsData
              : [{ title: "Loading notices..." }]
            )
              .concat(newsData) // duplicate for seamless loop
              .map((item, index) => (
                <li className="bulletin-item" key={index}>
                  <img
                    src="https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/DEMO9/public/images/arrow-1.gif"
                    className="bulletin-icon"
                    alt="St. Xavier"
                  />
                  <div className="bulletin-content">
                    <h5 className="bulletin-title">
                      {item.title || "No Title"}
                    </h5>
                    <p
                      className="bulletin-desc"
                      dangerouslySetInnerHTML={{
                        __html: item.description || "No Description",
                      }}
                    />
                  </div>
                </li>
              ))}
          </div>
        </div>
      </ul>

      <div className="row land">
        <div className="col-12  text-center">
          <a
            href="/news"
            className="btn thm-btns d-inline-flex align-items-center gap-2 "
          >
            <span>View All</span>
            <i className="bi bi-arrow-right"></i>
          </a>
        </div>
      </div>
    </>
  );
}

export default NoticeBoard;

