import React, { useEffect, useState } from "react";
import { getOnlineRegistration } from "../Service/Api";
import { Link } from "react-router-dom";

const OnlineRegistration = () => {
  const [item, setItem] = useState(null);

  const BASE_URL = "https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/";

  useEffect(() => {
    async function fetchReg() {
      let RegAwait = await getOnlineRegistration();
      console.log("what is RegAwait", RegAwait);

      if (RegAwait && RegAwait.length > 0) {
        const first = RegAwait[0];
        const d = new Date(first.date);

        setItem({
          _id: first._id,
          title: first.title,
          url: first.url,
          attachment: first.attachments?.[0] || null,
          dateText: d.toLocaleDateString("en-GB"),
        });
      }
    }
    fetchReg();
  }, []);

  if (!item) return null;

  return (
    <div class="oreg" id="Registration-content">
      <div className="OnlineR">
        <span className="blinker">
          {item.attachment && (
            <Link to={BASE_URL + item.attachment} target="_blank">
              <i className="bi bi-paperclip"></i>
            </Link>
          )}
          <Link to={item.url} target="_blank" className="parentlogo">
            {item.title}
          </Link>
        </span>
      </div>
    </div>
  );
};

export default OnlineRegistration;

