import React, { useEffect, useState } from "react";
import Slider from "react-slick";
import "slick-carousel/slick/slick.css";
import "slick-carousel/slick/slick-theme.css";
import { getTopper } from "../Service/Api";

function XIIToppers() {
  const [toppers, setToppers] = useState([]);

  useEffect(() => {
    const fetchToppers = async () => {
      try {
        const data = await getTopper();
        let mappedToppers = [];

        if (data && data.length > 0) {
          mappedToppers = data
            .filter((item) => item.class === "XII") // ✅ correct comparison
            .map((item) => ({
              image: item?.attachments?.[0]
                ? `https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/${item.attachments[0]}`
                : "https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/DEMO9/public/images/principle-d.jpg",
              score: item?.division || "",
              name: item?.name || "Student",
              subject: item?.stream || "",
            }));
        }

        // fallback dummy items
        if (mappedToppers.length === 0) {
          const fallbackCount = 2;
          mappedToppers = Array.from({ length: fallbackCount }, () => ({
            image:
              "https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/DEMO9/public/images/principle-d.jpg",
            score: "",
            name: "Student",
            subject: "",
          }));
        }

        setToppers(mappedToppers);
      } catch (error) {
        console.error("Error fetching toppers:", error);
        setToppers(
          Array.from({ length: 2 }, () => ({
            image:
              "https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/DEMO9/public/images/principle-d.jpg",
            score: "",
            name: "Student",
            subject: "",
          })),
        );
      }
    };

    fetchToppers();
  }, []);

  const settings = {
    dots: false,
    infinite: true,
    speed: 500,
    slidesToShow: 2,
    slidesToScroll: 1,
    autoplay: true,
    autoplaySpeed: 2000,
    cssEase: "linear",
    responsive: [
      { breakpoint: 1599, settings: { slidesToShow: 1, slidesToScroll: 1 } },
      { breakpoint: 991, settings: { slidesToShow: 1, slidesToScroll: 1 } },
      { breakpoint: 767, settings: { slidesToShow: 2, slidesToScroll: 1 } },
      { breakpoint: 600, settings: { slidesToShow: 1, slidesToScroll: 1 } },
      { breakpoint: 480, settings: { slidesToShow: 1, slidesToScroll: 1 } },
    ],
  };

  return (
    <div className="col-xl-4 col-lg-4 col-md-6 topper-xii">
      <div className="col-12">
        <h3 className="section-subtitle">Our shining stars</h3>
        <h2 className="section-title">XII Toppers</h2>
      </div>
      <div className="row">
        <Slider {...settings}>
          {toppers.map((topper, index) => (
            <div className="TopperSec" key={index}>
              <div className="topper-img-wrapper">
                <div className="topper-border">
                  <img
                    src={topper.image}
                    className="topper-img"
                    alt={topper.name}
                  />
                </div>
              </div>
              <div className="topper-info">
                <h3 className="topper-score">{topper.score}</h3>
                <h4>{topper.name}</h4>
                <h5>{topper.subject}</h5>
              </div>
            </div>
          ))}
        </Slider>
      </div>
    </div>
  );
}

export default XIIToppers;

