import React,{useState, useEffect} from 'react'
import Slider from 'react-slick';
import { Link } from 'react-router-dom';
import "slick-carousel/slick/slick.css";
import "slick-carousel/slick/slick-theme.css";
import {getBirthdays } from "../Service/Api"

function BirthDay() {
    const [birthData, setBirthData] =useState([]);
    const BASE_URL = "https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/";


    const DEFAULT_IMG =
  "https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/LCSBB/public/Images/default.jpg";

useEffect(() => {
  async function fetchBirthday() {
    try {
      let birthdayAwait = await getBirthdays();
      console.log("birthday data:", birthdayAwait);

      const formatted = birthdayAwait?.map((item) => {
        const d = item.date ? new Date(item.date) : null;

        return {
          _id: item._id,
          src: item.attachments?.[0]
            ? BASE_URL + item.attachments[0]
            : DEFAULT_IMG,
          name: item.name || "Unknown",
          class: item.class || "N/A",
          alt: item.name || "birthday image",

          year: d ? d.getFullYear().toString() : "",
          month: d ? (d.getMonth() + 1).toString() : "",

          dateText: d
            ? d.toLocaleDateString("en-GB", {
                day: "2-digit",
                month: "short",
              })
            : "",
        };
      });

      setBirthData(formatted || []);
    } catch (err) {
      console.error("Birthday fetch error:", err);
      setBirthData([]);
    }
  }

  fetchBirthday();
}, []);


    const dummy_birthday=[
        {
            src:"https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/LCSBB/public/Images/default.jpg",
            name:"",
            class:"",
            alt:"Loreto",
        },
    {
        src:"https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/LCSBB/public/Images/default.jpg",
        name:"",
        class:"",
        alt:"Loreto",
    },
  {
    src:"https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/LCSBB/public/Images/default.jpg",
    name:"",
    class:"",
    alt:"Loreto",
},];
    const filteredBirthday = birthData.length === 0 ? dummy_birthday : birthData;



    const settings = {
        dots: false,
        infinite: true,
        speed: 500,
        slidesToShow: 2,
        slidesToScroll: 1,
        autoplay: true,
        autoplaySpeed: 2000,
        cssEase: "linear",
        responsive: [
            {
                breakpoint: 1599,
                settings: { slidesToShow: 1, slidesToScroll: 1 }
            },
            {
                breakpoint: 991,
                settings: { slidesToShow: 2, slidesToScroll: 1 }
            },

            {
                breakpoint: 600,
                settings: { slidesToShow: 1, slidesToScroll: 1 }
            },


            {
                breakpoint: 480,
                settings: { slidesToShow: 1, slidesToScroll: 1 }
            }
        ]
    };
    return (
        <>
            <div className="col-xl-4 col-lg-4 col-md-12 ">
                <div className="col-12">
                    <h3 className="section-subtitle">Stars of the day</h3>
                    <h2 className="section-title">Birthday Section</h2>
                </div>
                <div className='row arrownone'>
                    <Slider {...settings}>
                    {filteredBirthday.map((item,index,arr) => (
                        <div className="BirthdaySec" key={index}>
                            <div className="birthday-img-wrapper">

                            <img
                            src={item.src}
                            className="birthday-img"
                            alt={item.alt}
                            onError={(e) => {
                              e.currentTarget.onerror = null;
                              e.currentTarget.src = DEFAULT_IMG;
                            }}
                          />
                                <img
                                    src="https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/LCSBB/public/Images/birtday.png"
                                    className="birthday-hover-img"
                                    alt="loretobowbazar"
                                />
                            </div>
                            <div className="birthday-info">
                                <h4>{item.name}</h4>
                                <h5>{item.class}</h5>
                            </div>
                            </div>))}
                    </Slider>
                </div>
                {/*<div className='text-center TopSpace'>
                    <a href="#" className="btn-custom-outline">
                        View All <img src="https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/LCSBB/public/Images/Arrow.gif" alt="loretobowbazar" />
                    </a>
                          </div>*/}
            </div>
        </>
    )
}

export default BirthDay

