import React, { useEffect, useState } from "react";
import Slider from 'react-slick';
import { Link } from 'react-router-dom';
import "slick-carousel/slick/slick.css";
import "slick-carousel/slick/slick-theme.css";
import {getGallery} from "../Service/Api.js"
function HomeGallery() {

    const [galleryData, setGalleryData] = useState([]);
    const BASE_URL =
    "https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/";

    useEffect(() => {
        async function fetchGalleryData() {
          const galleryAwait = await getGallery();

          const filtered = galleryAwait.filter(
            (item) => item.category === "PhotoGallery"
          );

          const formatted = filtered.map((item) => ({
            _id: item._id,
            alt: item.title,
            src: item.attachments?.length
              ? BASE_URL + item.attachments[0]
              : "",
            title: item.title,
          }));

          setGalleryData(formatted);
        }

        fetchGalleryData();
      }, []);


          const galleryImages = [
            {
                src: "https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/LCSBB/public/Images/gal-1.jpeg",
                alt: "Loreto",
                title: "Category Name",
                year: "2026",
                month: "1",
                date: "01/01/2026",
                description: "Stay tuned for latest images",
              },
            {
                src: "https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/LCSBB/public/Images/gal-1.jpeg",
                alt: "Loreto",
                title: "Category Name",
                year: "2026",
                month: "1",
                date: "01/01/2026",
                description: "Stay tuned for latest images",
              },
            {
              src: "https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/LCSBB/public/Images/gal-1.jpeg",
              alt: "Loreto",
              title: "Category Name",
              year: "2026",
              month: "1",
              date: "01/01/2026",
              description: "Stay tuned for latest images",
            },

          ];
          const filteredImages =
            galleryData.length === 0 ? galleryImages : galleryData;


            const slideCount = filteredImages.length;





    const settings = {
        dots: false,
        infinite: true,
        speed: 500,
        slidesToShow: 4,
        slidesToScroll: 1,
        autoplay: true,
        autoplaySpeed: 2000,
        cssEase: "linear",
        responsive: [
            {
                breakpoint: 1024,
                settings: { slidesToShow: 3, slidesToScroll: 1 }
            },
            {
                breakpoint: 991,
                settings: { slidesToShow: 2, slidesToScroll: 1 }
            },

            {
                breakpoint: 600,
                settings: { slidesToShow: 1, slidesToScroll: 1 }
            },
            {
                breakpoint: 480,
                settings: { slidesToShow: 1, slidesToScroll: 1 }
            }
        ]
    };
    return (
        <>
            <section className='GallerySec'>
                <div class="Gallery__shape">
                    <img class="Gallery-shape-1 img-fluid" src="https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/LCSBB/public/Images/gal-icon-1.png" alt="loretobowbazar" />
                    <img class="Gallery-shape-2 img-fluid" src="https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/LCSBB/public/Images/gal-icon-2.png" alt="loretobowbazar" />
                    <img class="Gallery-shape-3 img-fluid" src="https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/LCSBB/public/Images/gal-icon-3.png" alt="loretobowbazar" />
                </div>
                <div className='container-fluid'>
                    <div className='row'>
                        <div className='col-12'>
                            <h3 className='section-subtitle'>gallery section</h3>
                            <h2 className='section-title '>memories in images</h2>
                        </div>
                    </div>
                    <div className='row g-3'>
                        <Slider {...settings}>
                        {filteredImages.map((item, index) => (
                            <div className="gallery-wrap">
                                <div class="HomeGallery">
