import React, { useRef, useState, useEffect } from "react";
import { getNews } from "../Service/Api.js";
import { Link } from 'react-router-dom';

function HomeNews() {
    const [newsData, setNewsData] = useState([]);

    const marqueeRef = useRef(null);
    const handleMouseOver = () => marqueeRef.current.stop();
    const handleMouseOut = () => marqueeRef.current.start();

    const BASE_URL = "https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/";

  useEffect(() => {
    async function fetchNews() {
      let newsAwait = await getNews();
      console.log("what is newsAwait", newsAwait);

      const formatted = newsAwait.map((item) => {
        const d = new Date(item.fromDate);
        return {
          _id: item._id,
          src: item.attachments?.[0] ? BASE_URL + item.attachments[0] : "",
          title: item.title,
          desc: item.description,
          year: d.getFullYear().toString(),
          month: (d.getMonth() + 1).toString(),
          dateText: d.toLocaleDateString("en-GB"),
        };
      });
    setNewsData(formatted)
    }
    fetchNews();
  }, []);
  const dummy_news=[
    {
        src:"",
        title:"News will be available soon.",
        desc: "",
        dateText: "",
    },
];
const filteredNews = newsData.length === 0 ? dummy_news : newsData;

    return (
        <>
            <div className="NewsSec">
                <h4 className="subhead">Notice & Updates</h4>
                <h2 className="mainhead">Latest News</h2>
                <marquee
                    ref={marqueeRef}
                    direction="up"
                    onMouseOver={handleMouseOver}
                    onMouseOut={handleMouseOut} >
                    {filteredNews.map((item,index,arr) => (
                    <div className="news-content " key={index}>
                        <div className="news-left">
                            <div className="left-arrow">
                                <img src="https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/LCSBB/public/Images/arrow.png" alt="arrow" />
                            </div>

                            <div className="middle-info">
                                <h3 className="News-title">
                                {item.title}
                                </h3>
                            </div>
                        </div>


                        <div className="news-right">
                        {item.src && (
                            <div className="right-attach">
                              <Link to={item.src} target="_blank" className="mt-3 mt-md-2">
                              <img src="https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/LCSBB/public/Images/atta.png" alt="attach" />
                              </Link>
                              </div>
                            )}
                            <div className="news-date">
                            {item.dateText}
                            </div>
                        </div>
                    </div>





                    ))}

                </marquee>
                <br />
                <div className='text-end'>
                    <Link to="/news" className="btn-custom">
                        View All <img src="https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/LCSBB/public/Images/Arrow.gif" alt="attach" />
                    </Link>
                </div>
            </div>
            <div class="fixed-bottom-left">
                <img src="https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/LCSBB/public/Images/sapling.png" alt="attach" />
            </div>

        </>
    );
}
export default HomeNews;

