import React, { useEffect, useState } from 'react';
import Carousel from 'react-bootstrap/Carousel';
import { getSliders } from '../Service/Api';

const FALLBACK_IMAGE = 'https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/LCSBB/public/Images/sld-1.jpeg';
const S3_BASE_URL = 'https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/';

function Slider() {
    const [slides, setSlides] = useState([{ src: FALLBACK_IMAGE, _id: 'fallback-1' }]);

    useEffect(() => {
        const fetchSliders = async () => {
            try {
                const response = await getSliders();
                const sliderList = Array.isArray(response)
                    ? response
                    : Array.isArray(response?.data)
                        ? response.data
                        : [];

                const dynamicSlides = sliderList
                    .filter((item) => item?.attachment)
                    .sort((a, b) => (a?.position || 0) - (b?.position || 0))
                    .map((item) => ({
                        _id: item?._id || item?.attachment,
                        src: `${S3_BASE_URL}${item.attachment}`,
                        alt: item?.title || 'loretobowbazar',
                    }));

                if (dynamicSlides.length > 0) {
                    setSlides(dynamicSlides);
                } else {
                    setSlides([{ src: FALLBACK_IMAGE, _id: 'fallback-1', alt: 'loretobowbazar' }]);
                }
            } catch (error) {
                setSlides([{ src: FALLBACK_IMAGE, _id: 'fallback-1', alt: 'loretobowbazar' }]);
            }
        };

        fetchSliders();
    }, []);

    return (
        <Carousel>
            {slides.map((slide, index) => (
                <Carousel.Item key={slide._id || index}>
                    <img src={slide.src} alt={slide.alt || 'loretobowbazar'} className="d-block w-100" />
                </Carousel.Item>
            ))}
        </Carousel>
    );
}

export default Slider;

import React, { useEffect, useState } from "react";

const VisitorCounter = () => {
  const API_URL = "https://webapi.entab.info";
  const [visitorCount, setVisitorCount] = useState("000");

  // Function to post (increment) the visitor count
  const postVisitor = async () => {
    try {
      const response = await fetch(`${API_URL}/api/visitor`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ schoolcode: "LCSBB" }),
      });

      if (!response.ok) {
        throw new Error(`Error in POST request: ${response.status}`);
      }

      const data = await response.json();
      console.log("POST response:", data);
      return data;
    } catch (error) {
      console.error("Error incrementing visitor count:", error);
    }
  };

  // Function to fetch the current visitor count
  const getVisitor = async () => {
    try {
      const response = await fetch(
        `${API_URL}/api/visitor/LCSBB?timestamp=${new Date().getTime()}`
      );

      if (!response.ok) {
        throw new Error(`Error fetching visitor count: ${response.status}`);
      }

      return await response.json();
    } catch (error) {
      console.error("Error fetching visitor count:", error);
      return null;
    }
  };

  // Function to update visitor count
  const updateVisitorCount = (count) => {
    setVisitorCount(count.toString().padStart(3, "0"));
  };

  // Function to handle increment and fetch logic
  const incrementVisitor = async () => {
    await postVisitor();

    setTimeout(async () => {
      const visitorData = await getVisitor();
      if (visitorData && visitorData.length > 0) {
        updateVisitorCount(visitorData[0].visitor);
      }
    }, 500);
  };

  useEffect(() => {
    incrementVisitor();
  }, []);

  return (
    <div className="visitor_count">
      <h3>
        Visitor Counter: <span>{visitorCount}</span>
      </h3>
    </div>
  );
};

export default VisitorCounter;

