import React, { useState, useEffect } from "react";
import Slider from 'react-slick';
import { Link } from 'react-router-dom';
import "slick-carousel/slick/slick.css";
import "slick-carousel/slick/slick-theme.css";
import { getTopper } from "../Service/Api.js";
function XIIToppers() {

    const [toppersData, setToppersData] = useState([]);
  const BASE_URL = "https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/";

  useEffect(() => {
    async function fetchToppers() {
      let toppersAwait = await getTopper();

      const currentYear = new Date().getFullYear();
      let startYear = currentYear;
      let foundData = [];


      for (let i = 0; i < 5; i++) {
        let session = `${startYear - i}-${startYear - i + 1}`;

        let filtered = toppersAwait.filter(
          (item) => item.class === "XII" && item.sessionYear === session
        );

        if (filtered.length > 0) {
          foundData = filtered;
          break; 
        }
      }

      const formatted = foundData.map((item) => ({
        _id: item._id,
        src: item.attachments?.[0]
          ? BASE_URL + item.attachments[0]
          : "",
        name: item.name,
        percentage: item.division,
        subject: item.stream,
        alt: item.title,
      }));

      setToppersData(formatted);
    }

    fetchToppers();
  }, []);



    const settings = {
        dots: false,
        infinite: true,
        speed: 500,
        slidesToShow: 2,
        slidesToScroll: 1,
        autoplay: true,
        autoplaySpeed: 2000,
        cssEase: "linear",
        responsive: [
            {
                breakpoint: 1599,
                settings: { slidesToShow: 1, slidesToScroll: 1 }
            },
            {
                breakpoint: 991,
                settings: { slidesToShow: 1, slidesToScroll: 1 }
            },
            {
                breakpoint: 767,
                settings: { slidesToShow: 2, slidesToScroll: 1 }
            },
            {
                breakpoint: 600,
                settings: { slidesToShow: 1, slidesToScroll: 1 }
            },
            {
                breakpoint: 480,
                settings: { slidesToShow: 1, slidesToScroll: 1 }
            }
        ]
    };

    const dummy_toppers = [
        {
            src: "https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/LCSBB/public/Images/default.jpg",
            name: "",
            percentage: "",
            subject: "",
            alt: "Loreto",
          },
        {
            src: "https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/LCSBB/public/Images/default.jpg",
            name: "",
            percentage: "",
            subject: "",
            alt: "Loreto",
          },
        {
          src: "https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/LCSBB/public/Images/default.jpg",
          name: "",
          percentage: "",
          subject: "",
          alt: "Loreto",
        },
      ];
      const filteredToppers =
        toppersData.length === 0 ? dummy_toppers : toppersData;

    return (
        <>
            <div className="col-xl-6 col-lg-6  col-md-6">
                <div className="col-12">
                    <h2 className="section-title-topper">XII Toppers</h2>
                </div>
                <div className='row'>
                    <Slider {...settings}>
                {filteredToppers.map((item, index) => (
                  <div className="TopperSec" key={index}>
                    <div className="topper-img-wrapper">
                      <div className="topper-border">
                        {item.src && (
                          <img
                            src={item.src}
                            className="topper-img"
                            alt={item.alt}
                          />
                        )}
                      </div>
                    </div>

                    <div className="topper-info">
                      <h3 className="topper-score">{item.percentage}</h3>
                      <h4>{item.name}</h4>
                      <h5>{item.subject}</h5>
                    </div>
                  </div>
                ))}
              </Slider>
                </div>
                <div className='text-center TopSpace'>
                    <Link to="/toppers-xii" className="btn-custom-outline">
                        View All <img src="https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/LCSBB/public/Images/Arrow.gif" alt="loretobowbazar" />
                    </Link>
                </div>
            </div>
        </>
    )
}

export default XIIToppers

