      "The open book inside a triangle represents knowledge, transparency, and integrity—key pillars of the legal profession. The open book signifies the firm's commitment to education, learning and continuous growth in the legal field, ensuring that all strategies and decisions are backed by in-depth legal expertise. The triangle shape symbolizes stability, strength, and balance, as the firm uses well-rounded legal knowledge to guide its clients toward successful outcomes.  ",
    image: "/images/sld4.png",
  },
  {
    title: "Sengol",
    subtitle: " Symbol of Protection and Wisdom",
    para1:
      "The Sengol represents spiritual wisdom, protection, and guidance. For the firm, it symbolizes the protection of client interests and a commitment to ethical practices. It highlights the firm's role as a guiding force in navigating the complexities of law, ensuring clients are shielded from legal risks with wise counsel and strategic thinking",
    image: "/images/sld5.png",
  },
];



function Slider() {
  const [current, setCurrent] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      nextSlide();
    }, 6000); 

    return () => clearInterval(interval); 
  }, []);

  const nextSlide = () => {
    setCurrent((prev) => (prev + 1) % slides.length);
  };

  const prevSlide = () => {
    setCurrent((prev) => (prev - 1 + slides.length) % slides.length);
  };

  const slide = slides[current];

  return (
    <section className="Slider">
      <div className={`slider-sec ${current === 0 ? "first-slide" : "other-slide"}`}>
        <div className="container-fluid container-landing container-sld">
        <div className={`sld-area ${current === 0 ? "first-slide" : "other-slide"}`}>
            {/* TEXT */}
            <div className="sld-text-wrapper">
              <div className="top-btn">
                <p>Trusted Legal Partners</p>
              </div>

              <div className="landing-title">
                <h3>{slide.title}</h3>
                <h5>{slide.subtitle}</h5>
              </div>

              <div className="slider-para">
                <p>{slide.para1}</p>

              </div>

              <Link to="/contact-us"><div className="reach-us-btn">
                <p>Reach Out to Us</p>
              </div></Link>

              {/* ARROWS */}
              <div className="arrow">
                <div className="arrow1" onClick={prevSlide}>
                  <img src="/images/arrow1.png" className="img-fluid" />
                </div>
                <div className="arrow2" onClick={nextSlide}>
                  <img src="/images/arrow2.png" className="img-fluid" />
                </div>
              </div>
            </div>

            {/* IMAGE */}
            <div key={current} className="sld-img-wrapper">
              <img src={slide.image} alt="slide" />
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}

export default Slider;

