                const normalized = Array.isArray(response) ? response : [];
                const sorted = [...normalized].sort((a, b) => {
                    const dateA = new Date(a?.date);
                    const dateB = new Date(b?.date);
                    const timeA = Number.isNaN(dateA.getTime()) ? 0 : dateA.getTime();
                    const timeB = Number.isNaN(dateB.getTime()) ? 0 : dateB.getTime();
                    return timeB - timeA;
                });
                const latestSix = sorted.slice(0, 6).map((item) => ({
                    title: item?.title || "Untitled Video",
                    image: item?.attachments?.[0]
                        ? `https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/${item.attachments[0]}`
                        : "https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/MCSHJ/public/images/img-1.png",
                    alt: item?.title || "mountcarmelschoolhazaribagh",
                    videoUrl: item?.videoUrl || ""
                }));
                setVideos(ensureMinimumSlides(latestSix));
            } catch (error) {
                setVideos([]);
            }
        };

        fetchVideoGallery();
    }, []);

    const settings = {
