import "slick-carousel/slick/slick-theme.css";
import { getEvents } from '../Service/Api';
function HomeEvents() {
    const [eventsData, setEventsData] = useState([]);
    const BASE_URL = "https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/";

    useEffect(()=>{
        async function fetchEventsData(){
            let eventsAwait = await getEvents();

            console.log("What is eventsAwait", eventsAwait)
            const formatted = eventsAwait.map((item) => {
                const d = new Date(item.date);
                return {
                    _id: item._id,
                    src: item.images?.[0] ? BASE_URL + item.images[0] : "",
                    title: item.title,
                    time: item.time,
                    year: d.getFullYear().toString(),
                    month: (d.getMonth() + 1).toString(),
                    dateText: d.toLocaleDateString("en-GB"),
                };
              });
            setEventsData(formatted)
            }
            fetchEventsData();
          }, []);
          const dummy_events=[
            {
                src:"",
                title:"News will be available soon.",
                time:"",
                desc: "",
                dateText: "",
            },
                        {
                src:"",
                title:"News will be available soon.",
                time:"",
                desc: "",
                dateText: "",
            },
                        {
                src:"",
                title:"News will be available soon.",
                time:"",
                desc: "",
                dateText: "",
            },
                        {
                src:"",
                title:"News will be available soon.",
                time:"",
                desc: "",
                dateText: "",
            },
        ];
        const filteredEvents = eventsData.length === 0 ? dummy_events : eventsData;

    const settings = {
        dots: false,
        infinite: true,
        speed: 500,
        slidesToShow: 4,
        slidesToScroll: 1,
        autoplay: true,
        autoplaySpeed: 2000,
        cssEase: "linear",
        responsive: [
            {
                breakpoint: 1599,
                settings: { slidesToShow: 3, slidesToScroll: 1 }
            },
            {
                breakpoint: 991,
                settings: { slidesToShow: 2, slidesToScroll: 1 }
            },

            {
                breakpoint: 600,
                settings: { slidesToShow: 1, slidesToScroll: 1 }
            },
            {
                breakpoint: 480,
                settings: { slidesToShow: 1, slidesToScroll: 1 }
            }
        ]
    };
    return (
        <>
            <section className='EventSec'>
                        <Slider {...settings}>
                        {filteredEvents.map((item,index) => (
                            <div className='EventBox'  key={index}>
                                <img src={item.src}/>
                                <h3>{item.title}</h3>
                                <div>
                                    <h6 className="date-time">
                                        <span className="date-block">
                                            <i className="bi bi-calendar"></i>
                                            {item.dateText}
                                        </span>
                                        <span className="time-block">
                                            <i class="bi bi-clock"></i>
                                            {item.time}
                                        </span>
                                    </h6>
                                </div>
                            </div>
                        ))}

                        </Slider>


                    <div className='row'>
