import React, { useRef, useState, useEffect } from "react";
import { getNews } from "../Service/Api.js";


function HomeNews() {
  const [newsData, setNewsData] = useState([]);
  const marqueeRef = useRef(null);

  const handleMouseOver = () => marqueeRef.current.stop();
  const handleMouseOut = () => marqueeRef.current.start();

 const BASE_URL = "https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/";

  useEffect(() => {
    async function fetchNews() {
      let newsAwait = await getNews();
      console.log("what is newsAwait", newsAwait);

      const formatted = newsAwait.map((item) => {
        const d = new Date(item.fromDate);
        return {
          _id: item._id,
          src: item.attachments?.[0] ? BASE_URL + item.attachments[0] : "",
          title: item.title,
          desc: item.description,
          year: d.getFullYear().toString(),
          month: (d.getMonth() + 1).toString(),
          dateText: d.toLocaleDateString("en-GB"),
        };
      });
    setNewsData(formatted)
    }
    fetchNews();
  }, []);
  const dummy_news=[
    {
        src:"",
        title:"News will be available soon.",
        desc: "",
        dateText: "",
    },
];
const filteredNews = newsData.length === 0 ? dummy_news : newsData;

  return (
    <> 
      <ul className="bulletin-list">
        <h6>Key Dates and School Happenings</h6>
        <h2>Our School Bulletin</h2>
        <marquee
          ref={marqueeRef}
          direction="up"
          scrollAmount="3"
          onMouseOver={handleMouseOver}
          onMouseOut={handleMouseOut}
        >{filteredNews.map((item,index,arr) => (
          <li className="bulletin-item"  key={index}>
            <img
              src="https://entab-s3-bucket1.s3.ap-south-1.amazonaws.com/MCSHJ/public/images/arrow-1.gif"
              className="bulletin-icon"
              alt="Carmel School Hazaribagh"
            />

            <div className="bulletin-content" >
              <h5 className="bulletin-title">{item.title}</h5>
              <p className="bulletin-desc">{item.desc}</p>
              <div className="bulletin-schedule" >
                <p >{item.dateText}</p>
              </div>
              {item.src && (
              <div className="bulletin-attachment">
                <a href={item.src} target="_blank" className="mt-3 mt-md-2">
                  <h6 className="loc mb-0"><span> View Attachment</span></h6>
                </a>
                </div>
              )}
              </div>


          </li>
          ))}
        </marquee>
      </ul>

    </>
  );
}

export default HomeNews;

